import * as React from 'react';
import clsx from 'clsx';
import { ListBox } from '../shared/components/list/List';
import type { TransferOption, TransferProps, TransferRef, TransferValue } from './interface';
import { TransferProvider, useTransfer } from './hooks/TransferContext';
import { useCssScope } from '../config-provider';
import { TransferSourcePanel } from './panel/SourcePanel';
import { TransferTargetPanel } from './panel/TargetPanel';
import { sxTransfer } from './sx';

export const Transfer = React.forwardRef(
  <V extends TransferValue, OP extends TransferOption<V>>(
    props: React.PropsWithChildren<TransferProps<V, OP>>,
    ref: React.Ref<TransferRef>,
  ) => {
    const cssScope = useCssScope('transfer');

    const defaultChildren = React.useMemo(
      () => (
        <>
          <TransferSourcePanel />
          <TransferTargetPanel />
        </>
      ),
      [],
    );

    const { children = defaultChildren, style, className, ...useTransferProps } = props;

    const ctxValue = useTransfer<V, OP>(useTransferProps);

    React.useImperativeHandle(ref, () => ({
      clearSearchValue: () => ctxValue.setSearchValue(''),
    }));

    return (
      <TransferProvider value={ctxValue}>
        <ListBox cascaded style={style} sx={[sxTransfer]} className={clsx(cssScope(), className)}>
          {children}
        </ListBox>
      </TransferProvider>
    );
  },
) as <T extends TransferValue, Op extends TransferOption<T>>(
  props: React.PropsWithChildren<TransferProps<T, Op>> & {
    ref?: React.Ref<TransferRef>;
  },
) => React.ReactElement;
